  function getUpdateProgress(log: string[]): { step: number; pct: number } {
    const j = log.join('\n')
    if (j.includes('RESTARTING'))                                         return { step: 4, pct: 95 }
    if (j.includes('Migrations applied') || j.includes('Migrations done')) return { step: 3, pct: 75 }
    if (j.includes('Running database'))                                    return { step: 3, pct: 55 }
    if (j.includes('Packages ready'))                                      return { step: 2, pct: 50 }
    if (j.includes('Installing packages'))                                 return { step: 2, pct: 30 }
    if (j.includes('Updated to v'))                                        return { step: 1, pct: 25 }
    if (j.includes('Pulling'))                                             return { step: 1, pct: 10 }
    return { step: 0, pct: 0 }
  }

  async function startUpdate() {
    setUpdateRunning(true)
    setUpdateLog([])
    setUpdateDone(false)
    setUpdateSuccess(false)
    setUpdateCountdown(null)
    const r = await fetch('/api/system/update', { method: 'POST' })
    const d = await r.json().catch(() => ({}))
    if (!d.started) {
      setUpdateLog([d.error ?? 'Failed to start update'])
      setUpdateRunning(false)
      return
    }
    // Poll for status
    updatePollRef.current = setInterval(async () => {
      try {
        const sr = await fetch('/api/system/update/status')
        const sd = await sr.json()
        setUpdateLog(sd.log ?? [])
        if (sd.restarting) {
          setUpdateSuccess(true)
          setUpdateDone(true)
          setUpdateRunning(false)
          clearInterval(updatePollRef.current)
          // Start 12-second countdown then auto-refresh
          let secs = 12
          setUpdateCountdown(secs)
          countdownRef.current = setInterval(() => {
            secs--
            if (secs <= 0) {
              clearInterval(countdownRef.current)
              window.location.reload()
            } else {
              setUpdateCountdown(secs)
            }
          }, 1000)
        } else if (sd.finished) {
          setUpdateSuccess(sd.success)
          setUpdateDone(true)
          setUpdateRunning(false)
          clearInterval(updatePollRef.current)
          loadVersionInfo()
        }
      } catch {}
    }, 1500)
  }

