  async function addDept(label: string, key?: string) {
    const trimmed = label.trim()
    if (!trimmed) { showToast('Enter a department name'); return }
    const maxDepts = license?.maxDepartments ?? -1
    if (maxDepts !== -1 && depts.length >= maxDepts) { showToast(`Department limit reached (${maxDepts}). Ask your super admin to increase it.`); return }
    const deptKey = key ?? trimmed.toUpperCase().replace(/\s+/g, '_').replace(/[^A-Z0-9_]/g, '')
    const r = await fetch('/api/tenant/departments', {
      method:'POST',
      headers:{'Content-Type':'application/json'},
      body: JSON.stringify({ department: deptKey, label: trimmed })
    })
    const d = await r.json().catch(() => ({}))
    if (d.success) { showToast(`"${trimmed}" department added`); loadDepts(); setNewDeptName('') }
    else showToast('Error: ' + d.error)
  }

