    setKbSaving(true)
    const r = await fetch('/api/tenant/kb', { method: kbEditing ? 'PATCH' : 'POST', headers:{'Content-Type':'application/json'}, body: JSON.stringify(payload) })
    const d = await r.json().catch(() => ({}))
